#include <iostream>
#include <deque>

using namespace std;

int main()
{
    deque<int> numbers;
    numbers.push_back(20);
    numbers.push_front(10);
    numbers.push_back(30);

    for (int i = 0; i < numbers.size(); i++)
    {
        cout << numbers[i] << " ";
    }

    return 0;
}

